var e=[{id:`L2_1`,type:`dialog`,speaker:`LAIKA_SPACESUIT_NULL_NULL`,text:{KOREA:`좋아! 까짓 거 기분 내키면 단둘이 있을 땐, 주인님이라고 불러주지.`,JPN:`よし！　気が向いたらさ、2人きりの時にはご主人様って呼んであげてもいいよ。`,ENG:`Fine! If I'm in the mood, I'll even call you "Master" when we're alone`,TWN:`好吧！要是我心情好的話，二個人獨處時也可以叫你主人啦。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`LAIKA_SPACESUIT_NULL_NULL`,face:`UNIT_PRIDE`},R:null}}},{id:`L3_1`,type:`dialog`,speaker:`LAIKA_SPACESUIT_NULL_NULL`,text:{KOREA:`크흠, 그렇다고 너무 막 다루지는 말라고? 총이든 메이드든 마지막까지 가장 중요한 건, 서로간의 신뢰성이니까.`,JPN:`こほん、だからってこき使うなよ？　銃もメイドも最後まで一番重要なのは、お互いの信頼なんだからさ。`,ENG:`Ahem, just don't get carried away, all right? Whether it's a gun or a maid, what matters most in the end is trust.`,TWN:`咳咳，不過你可別太得寸進尺喔？不管是槍還是女僕，最重要的，是彼此的信任。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`LAIKA_SPACESUIT_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}}];export{e as default};